namespace sv_fa18543f473f4133a8516d976249cdd4.Services;

public class WarehouseInfo
{
    public string Id { get; set; } = "WH-001";
    public string Name { get; set; } = "Warehouse A";
}

public class WarehouseState
{
    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];

    public string SelectedWarehouseId { get; private set; } = "WH-001";

    public string SelectedWarehouseName =>
        Array.Find(AvailableWarehouses, w => w.Id == SelectedWarehouseId).Name
        ?? "Unknown";

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (SelectedWarehouseId == warehouseId) return;
        SelectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_fa18543f473f4133a8516d976249cdd4.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts per warehouse.
/// Fires OnAlertCountChanged so all subscribed components update together.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query returning the number of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Called by the polling component to refresh the count and notify all subscribers.
    /// </summary>
    public async Task RefreshAlertCountAsync(string warehouseId)
    {
        CurrentAlertCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }
}

@using sv_fa18543f473f4133a8516d976249cdd4.Services
@inject WarehouseState Warehouse
@implements IDisposable

<div class="d-flex align-items-center">
    <label class="me-2 text-nowrap mb-0" for="warehouse-select">
        <strong>Warehouse:</strong>
    </label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@Warehouse.SelectedWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseState.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? WarehouseInfo { get; set; }

    // Inject the CascadingValueSource so we can push updates across render modes
    [Inject]
    private CascadingValueSource<WarehouseInfo> WarehouseSource { get; set; } = default!;

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString() ?? "WH-001";
        Warehouse.SetWarehouse(newId);

        // Push the new warehouse info to all [CascadingParameter] subscribers
        var info = new WarehouseInfo
        {
            Id = Warehouse.SelectedWarehouseId,
            Name = Warehouse.SelectedWarehouseName
        };
        await WarehouseSource.NotifyChangedAsync(info);
    }

    private Action? _handler;

    protected override void OnInitialized()
    {
        // Also react if another component changes the warehouse via the scoped service
        _handler = () => InvokeAsync(StateHasChanged);
        Warehouse.OnChange += _handler;
    }

    public void Dispose()
    {
        Warehouse.OnChange -= _handler;
    }
}

