@rendermode InteractiveServer

@using sv_fa18543f473f4133a8516d976249cdd4.Services
@inject WarehouseState Warehouse
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-4">@Warehouse.SelectedWarehouseName</p>
                <p class="text-muted">@Warehouse.SelectedWarehouseId</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card @(alertCount > 5 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="card-text fs-1 @(alertCount > 5 ? "text-danger" : "text-success")">
                    @alertCount
                </p>
                <p class="text-muted">Items below minimum level</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text">
                    @if (_isPolling)
                    {
                        <span class="text-success">● Active</span>
                    }
                    else
                    {
                        <span class="text-muted">○ Stopped</span>
                    }
                </p>
                <p class="text-muted">Refreshes every 10 seconds</p>
            </div>
        </div>
    </div>
</div>

@if (alertCount > 0)
{
    <div class="alert @(alertCount > 5 ? "alert-danger" : "alert-warning") mt-4">
        <strong>⚠ Attention:</strong> @alertCount item(s) in <strong>@Warehouse.SelectedWarehouseName</strong>
        are below their minimum stock level. Review and reorder as needed.
    </div>
}
else
{
    <div class="alert alert-success mt-4">
        ✅ All items in <strong>@Warehouse.SelectedWarehouseName</strong> are above minimum stock levels.
    </div>
}

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private int alertCount;
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override async Task OnInitializedAsync()
    {
        // Subscribe to warehouse changes so we refresh immediately on switch
        _warehouseHandler = () => InvokeAsync(async () =>
        {
            await AlertService.RefreshAlertCountAsync(Warehouse.SelectedWarehouseId);
            StateHasChanged();
        });
        Warehouse.OnChange += _warehouseHandler;

        // Subscribe to alert changes (fired by RefreshAlertCountAsync) so this
        // component updates even if another component triggered the refresh
        _alertHandler = () => InvokeAsync(() =>
        {
            alertCount = AlertService.CurrentAlertCount;
            StateHasChanged();
        });
        AlertService.OnAlertCountChanged += _alertHandler;

        // Initial fetch
        await AlertService.RefreshAlertCountAsync(Warehouse.SelectedWarehouseId);
        alertCount = AlertService.CurrentAlertCount;

        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _isPolling = true;

        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await InvokeAsync(async () =>
                {
                    await AlertService.RefreshAlertCountAsync(Warehouse.SelectedWarehouseId);
                    // alertCount is updated via the OnAlertCountChanged handler
                });
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose
        }
    }

    public void Dispose()
    {
        _isPolling = false;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
        Warehouse.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

namespace sv_fa18543f473f4133a8516d976249cdd4.Services;

public class WarehouseInfo
{
    public string Id { get; set; } = "WH-001";
    public string Name { get; set; } = "Warehouse A";
}

public class WarehouseState
{
    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];

    public string SelectedWarehouseId { get; private set; } = "WH-001";

    public string SelectedWarehouseName =>
        Array.Find(AvailableWarehouses, w => w.Id == SelectedWarehouseId).Name
        ?? "Unknown";

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (SelectedWarehouseId == warehouseId) return;
        SelectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

