+
+<h1>Warehouse Dashboard</h1>
+
+<div class="row mt-4">
+    <div class="col-md-4">
+        <div class="card">
+            <div class="card-body text-center">
+                <h5 class="card-title">Current Warehouse</h5>
+                <p class="card-text fs-4">@Warehouse.SelectedWarehouseName</p>
+                <p class="text-muted">@Warehouse.SelectedWarehouseId</p>
+            </div>
+        </div>
+    </div>
+
+    <div class="col-md-4">
+        <div class="card @(alertCount > 5 ? "border-danger" : "border-success")">
+            <div class="card-body text-center">
+                <h5 class="card-title">Low-Stock Alerts</h5>
+                <p class="card-text fs-1 @(alertCount > 5 ? "text-danger" : "text-success")">
+                    @alertCount
+                </p>
+                <p class="text-muted">Items below minimum level</p>
+            </div>
+        </div>
+    </div>
+
+    <div class="col-md-4">
+        <div class="card">
+            <div class="card-body text-center">
+                <h5 class="card-title">Polling Status</h5>
+                <p class="card-text">
+                    @if (_isPolling)
+                    {
+                        <span class="text-success">● Active</span>
+                    }
+                    else
+                    {
+                        <span class="text-muted">○ Stopped</span>
+                    }
+                </p>
+                <p class="text-muted">Refreshes every 10 seconds</p>
+            </div>
+        </div>
+    </div>
+</div>
+
